const targets = $input.all().map(i => i.json);

// Mobile User-Agents only — widget renders only on mobile
const mobileUAs = [
  'Mozilla/5.0 (iPhone; CPU iPhone OS 17_3 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/17.3 Mobile/15E148 Safari/604.1',
  'Mozilla/5.0 (Linux; Android 14; SM-S918B) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.6261.64 Mobile Safari/537.36',
  'Mozilla/5.0 (Linux; Android 13; Pixel 7) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/122.0.6261.64 Mobile Safari/537.36',
  'Mozilla/5.0 (iPhone; CPU iPhone OS 16_6 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/16.6 Mobile/15E148 Safari/604.1'
];

const referers = [
  'https://www.google.com/',
  'https://yandex.ru/',
  'https://www.bing.com/',
  'https://dzen.ru/',
  ''
];

const TIMEZONE_MAP = {
  'FI': 3, 'RU': 3, 'KZ': 6, 'DE': 2, 'US': -5,
  'UA': 3, 'BY': 3, 'PL': 2, 'TR': 3, 'JP': 9,
  'IN': 5, 'BR': -3, 'GB': 1, 'FR': 2, 'IT': 2,
  'ES': 2, 'PT': 1, 'NL': 2, 'SE': 2, 'NO': 2,
  'CZ': 2, 'AT': 2, 'CH': 2, 'BE': 2, 'RO': 3,
  'TH': 7, 'VN': 7, 'ID': 7, 'PH': 8, 'MY': 8
};

const LANG_MAP = {
  'FI': 'fi-FI,fi;q=0.9,en;q=0.8',
  'RU': 'ru-RU,ru;q=0.9,en;q=0.8',
  'KZ': 'kk-KZ,kk;q=0.9,ru-RU;q=0.8,ru;q=0.7',
  'DE': 'de-DE,de;q=0.9,en;q=0.8',
  'US': 'en-US,en;q=0.9',
  'UA': 'uk-UA,uk;q=0.9,ru;q=0.8',
  'BY': 'ru-BY,ru;q=0.9,en;q=0.8',
  'PL': 'pl-PL,pl;q=0.9,en;q=0.8',
  'TR': 'tr-TR,tr;q=0.9,en;q=0.8',
  'JP': 'ja-JP,ja;q=0.9,en;q=0.8',
  'IN': 'hi-IN,hi;q=0.9,en-IN;q=0.8,en;q=0.7',
  'BR': 'pt-BR,pt;q=0.9,en;q=0.8',
  'GB': 'en-GB,en;q=0.9',
  'FR': 'fr-FR,fr;q=0.9,en;q=0.8',
  'IT': 'it-IT,it;q=0.9,en;q=0.8',
  'ES': 'es-ES,es;q=0.9,en;q=0.8',
  'TH': 'th-TH,th;q=0.9,en;q=0.8',
  'VN': 'vi-VN,vi;q=0.9,en;q=0.8'
};

// DataImpulse proxy: auto-generate proxy URL from bot_config + country_code
// If scan_target has manual proxy_url — use it as override
// buildProxyUrl(target, cc) — with geo for render
// buildProxyUrl(target, '') — without geo for page fetch (some sites block geo IPs)
function buildProxyUrl(target, cc) {
  if (target.proxy_url && target.proxy_url.trim()) {
    return target.proxy_url.trim();
  }
  const login = (target.di_login || '').trim();
  const pass = (target.di_password || '').trim();
  const host = (target.di_host || 'gw.dataimpulse.com').trim();
  const port = (target.di_port || '823').toString().trim();
  if (!login || !pass) return '';
  if (cc) {
    const userWithGeo = login + '__cr.' + cc.toLowerCase();
    const encUser = encodeURIComponent(userWithGeo);
    const encPass = encodeURIComponent(pass);
    return `http://${encUser}:${encPass}@${host}:${port}`;
  }
  const encUser = encodeURIComponent(login);
  const encPass = encodeURIComponent(pass);
  return `http://${encUser}:${encPass}@${host}:${port}`;
}

return targets.map(t => {
  const cc = (t.country_code || '').trim();
  const proxyUrlGeo = buildProxyUrl(t, cc);
  const proxyUrlNoGeo = buildProxyUrl(t, '');
  return {
    json: {
      target_id: t.id,
      site_url: (t.site_url || '').trim(),
      country_code: cc,
      proxy_url: proxyUrlGeo,
      proxy_url_page: proxyUrlNoGeo,
      proxy_type: proxyUrlGeo.startsWith('socks') ? 'socks5' : 'http',
      proxy_auto: !t.proxy_url || !t.proxy_url.trim(),
      user_agent: mobileUAs[Math.floor(Math.random() * mobileUAs.length)],
      referer: referers[Math.floor(Math.random() * referers.length)],
      timezone: t.timezone || TIMEZONE_MAP[cc] || 3,
      accept_language: t.accept_language || LANG_MAP[cc] || 'en-US,en;q=0.9',
      cached_render_domain: t.render_domain || null,
      cached_block_uuids: t.block_uuids || null,
      cached_extra_params: t.extra_params || null,
      cached_geozo_block_id: t.geozo_block_id || null
    }
  };
});

// Process ALL proxy responses, not just the first one
const items = $input.all();
const scanRequests = $('Prepare Scan Requests').all().map(i => i.json);

const MAX_REFRESHES = 5;

function genUuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}

const results = [];

for (let idx = 0; idx < items.length; idx++) {
  const input = items[idx].json;
  const html = input.data || input.body || (typeof input === 'string' ? input : '');
  const scanReq = idx < scanRequests.length ? scanRequests[idx] : scanRequests[0];
  const siteUrl = scanReq.site_url;
  const geo = scanReq.country_code;
  const proxyUrl = scanReq.proxy_url;
  const userAgent = scanReq.user_agent;
  const tz = scanReq.timezone || 3;
  const acceptLang = scanReq.accept_language || 'en-US,en;q=0.9';

  if (input.error || input.code >= 400) {
    results.push({ json: {
      site_url: siteUrl,
      country_code: geo,
      widget_found: false,
      block_ids: [],
      error: input.error || `HTTP ${input.code || 'unknown'}`,
      proxy_url: proxyUrl,
      scanned_at: $now.toISO()
    }});
    continue;
  }

  // --- Always use render.geozo.com as render domain ---
  const renderDomain = 'render.geozo.com';

  // Find data-gz-block UUIDs
  const blockIds = [];
  const seen = new Set();
  const blockRegex1 = /data-gz-block=["']([0-9a-f-]{36})["']/gi;
  let m;
  while ((m = blockRegex1.exec(html)) !== null) {
    if (!seen.has(m[1])) { seen.add(m[1]); blockIds.push(m[1]); }
  }
  const blockRegex2 = /data-gz-block=\\+["']([0-9a-f-]{36})\\+["']/gi;
  while ((m = blockRegex2.exec(html)) !== null) {
    if (!seen.has(m[1])) { seen.add(m[1]); blockIds.push(m[1]); }
  }

  // Parse extra data-* attributes from block div
  const extraParams = {};
  const blockDivRegex = /<div[^>]*data-gz-block=["'][0-9a-f-]{36}["']([^>]*)>/gi;
  const bdm = blockDivRegex.exec(html);
  if (bdm && bdm[1]) {
    const attrRegex = /data-([a-z0-9_]+)=["']([^"']+)["']/gi;
    let am;
    while ((am = attrRegex.exec(bdm[1])) !== null) {
      if (am[1] !== 'gz-block') extraParams[am[1]] = am[2];
    }
  }

  // Fallback: if no block UUIDs found in HTML, use cached from DB
  if (blockIds.length === 0 && scanReq.cached_block_uuids) {
    try {
      const cached = typeof scanReq.cached_block_uuids === 'string' ? JSON.parse(scanReq.cached_block_uuids) : scanReq.cached_block_uuids;
      const arr = Array.isArray(cached) ? cached : [cached];
      arr.forEach(id => {
        const s = String(id).trim();
        if (/^[0-9a-f-]{36}$/.test(s) && !seen.has(s)) { seen.add(s); blockIds.push(s); }
      });
    } catch(e) { /* ignore parse errors */ }
  }

  if (blockIds.length === 0) {
    results.push({ json: {
      site_url: siteUrl,
      country_code: geo,
      widget_found: false,
      block_ids: [],
      render_url: '',
      render_domain: renderDomain,
      proxy_url: proxyUrl,
      user_agent: userAgent,
      accept_language: acceptLang,
      scanned_at: $now.toISO()
    }});
    continue;
  }

  // Generate N render URLs per proxy with different UUIDs
  const blockUuid = blockIds[0];
  for (let round = 0; round < MAX_REFRESHES; round++) {
    const surferUuid = genUuid();
    const pageLoadUuid = genUuid();
    // Build extra params string from data-* attributes
    let extraQs = '';
    for (const [k, v] of Object.entries(extraParams)) {
      extraQs += `&${encodeURIComponent(k)}=${encodeURIComponent(v)}`;
    }
    const renderUrl = `https://${renderDomain}/v5/render?surfer_uuid=${surferUuid}&referrer=${encodeURIComponent(siteUrl)}&pre_referrer=${encodeURIComponent(siteUrl)}&time_zone=${tz}&page_load_uuid=${pageLoadUuid}&page_depth=1&block_uuid=${blockUuid}&refresh_depth=${round + 1}${extraQs}`;
    results.push({ json: {
      site_url: siteUrl,
      country_code: geo,
      widget_found: true,
      block_ids: blockIds,
      render_url: renderUrl,
      render_domain: renderDomain,
      refresh_round: round + 1,
      proxy_url: proxyUrl,
      user_agent: userAgent,
      accept_language: acceptLang,
      scanned_at: $now.toISO()
    }});
  }
}

if (results.length === 0) {
  return [{ json: { widget_found: false, block_ids: [], error: 'No valid responses from any proxy' } }];
}
return results;

// Parse teasers from merged HTML — parse each <a> teaser block as a unit
const input = $input.first().json;
const renderHtml = input.data || '';
const siteUrl = input.site_url;
const geo = input.country_code;
const renderDomain = input.render_domain || '';

if (!renderHtml || renderHtml.length < 50) {
  return [{ json: {
    site_url: siteUrl, country_code: geo, widget_found: true,
    block_ids: input.block_ids, render_domain: renderDomain,
    teasers_found: 0, teasers: [],
    error: 'No render HTML after merge', scanned_at: input.scanned_at
  }}];
}

const allTeasers = new Map();
let position = 0;

// Parse each <a> tag as a complete teaser unit
// Real HTML: <a ... href="click_url" ... class="...media ...block__item" ...>inner</a>
for (const m of renderHtml.matchAll(/<a\b([^>]*)>([\s\S]*?)<\/a>/gi)) {
  const attrs = m[1];
  const inner = m[2];
  // Must have class containing 'media' (widget teaser links)
  const classMatch = attrs.match(/class=["']([^"']+)["']/i);
  if (!classMatch || !classMatch[1].includes('media')) continue;

  // Extract click URL from href
  const hrefMatch = attrs.match(/href=["']([^"']+)["']/i);
  const clickUrl = hrefMatch ? hrefMatch[1].replace(/&amp;/g, '&') : '';

  // Extract title from media__title element
  const titleMatch = inner.match(/class=["'][^"']*media__title[^"']*["'][^>]*>\s*([\s\S]*?)\s*<\/\w+>/i);
  const title = titleMatch ? titleMatch[1].replace(/<[^>]+>/g, '').trim() : '';
  if (title.length <= 3) continue;

  position++;

  // Extract media_id from click URL
  let mediaId = null;
  const mediaMatch = clickUrl.match(/media=(\d+)/);
  if (mediaMatch) mediaId = mediaMatch[1];

  // Extract image URL from background-image or <img src>
  let imageUrl = null;
  const bgMatch = inner.match(/class=["'][^"']*media__img[^"']*["'][^>]*style=["'][^"']*background-image:\s*url\(['\"]?([^'\")]+)['\"]?\)/i);
  if (bgMatch) {
    imageUrl = bgMatch[1].replace(/&amp;/g, '&').replace(/&#39;/g, '').replace(/&quot;/g, '').replace(/^['"]|['"]$/g, '');
    if (!imageUrl.startsWith('http')) imageUrl = null;
  }
  if (!imageUrl) {
    const imgMatch = inner.match(/<img[^>]*src=["']([^"']+)["']/i);
    if (imgMatch) {
      imageUrl = imgMatch[1].replace(/&amp;/g, '&');
      if (!imageUrl.startsWith('http')) imageUrl = null;
    }
  }

  // Short description
  const sdMatch = inner.match(/class=["'][^"']*media__shortDesc[^"']*["'][^>]*>\s*([\s\S]*?)\s*<\/\w+>/i);
  const shortDesc = sdMatch ? sdMatch[1].replace(/<[^>]+>/g, '').trim() : null;

  // Full description
  const fdMatch = inner.match(/class=["'][^"']*media__fullDesc[^"']*["'][^>]*>\s*([\s\S]*?)\s*<\/\w+>/i);
  const fullDesc = fdMatch ? fdMatch[1].replace(/<[^>]+>/g, '').trim() : null;

  // Button text
  const btnMatch = inner.match(/class=["'][^"']*media__btn[^"']*["'][^>]*>\s*([\s\S]*?)\s*<\/\w+>/i);
  const btnText = btnMatch ? btnMatch[1].replace(/<[^>]+>/g, '').trim() : null;

  const teaser = {
    position,
    title,
    media_id: mediaId,
    click_url: clickUrl || null,
    image_url: imageUrl,
    short_description: shortDesc,
    full_description: fullDesc,
    button_text: btnText,
    appearances: 1
  };

  // Dedup: by media_id if available, otherwise by title
  const key = mediaId ? ('m:' + mediaId) : ('t:' + title);
  if (!allTeasers.has(key)) {
    allTeasers.set(key, teaser);
  } else {
    const existing = allTeasers.get(key);
    existing.appearances += 1;
    if (teaser.click_url) existing.click_url = teaser.click_url;
    if (teaser.position < existing.position) existing.position = teaser.position;
  }
}

const totalRenders = input.total_renders || 1;
const uniqueTeasers = Array.from(allTeasers.values());
uniqueTeasers.forEach(t => {
  t.show_rate = parseFloat((t.appearances / totalRenders).toFixed(4));
});

return [{ json: {
  site_url: siteUrl,
  country_code: geo,
  widget_found: true,
  block_ids: input.block_ids,
  render_domain: renderDomain,
  teasers_found: uniqueTeasers.length,
  total_renders: input.total_renders,
  renders_with_data: input.renders_with_data,
  teasers: uniqueTeasers,
  scanned_at: input.scanned_at
}}];

// Filter out teasers already in DB by media_id
// RATE LIMIT: max 4 NEW + 2 RE-CHECK per scan
// IMPORTANT: skip OUR teasers (from teasers table) — clicking costs money!
const knownRows = $input.all().map(i => i.json);

// Build maps: media_id -> row data (from DB)
const knownByMediaId = new Map();
const ourAdIds = new Set();
knownRows.forEach(r => {
  if (r.source === 'ours' && r.media_id) {
    ourAdIds.add(String(r.media_id));
  } else if (r.media_id) {
    knownByMediaId.set(String(r.media_id), r);
  }
});

const data = $('Parse Teasers from Render').first().json;
const teasers = data.teasers || [];
const siteUrl = data.site_url;
const geo = data.country_code;
const renderDomain = data.render_domain || '';
const proxyUrl = $('Prepare Scan Requests').first().json.proxy_url || '';

if (teasers.length === 0) {
  return [{ json: { skip: true, site_url: siteUrl, country_code: geo } }];
}

function parseTrackingParams(url) {
  if (!url || typeof url !== 'string') return {};
  url = url.replace(/&amp;/g, '&');
  const domainMatch = url.match(/https?:\/\/([^/?#]+)/);
  const domain = domainMatch ? domainMatch[1] : null;
  const qIdx = url.indexOf('?');
  if (qIdx === -1) return { landing_domain: domain };
  const qs = url.substring(qIdx + 1);
  const p = {};
  qs.split('&').forEach(pair => {
    const eq = pair.indexOf('=');
    if (eq > 0) p[pair.substring(0, eq)] = decodeURIComponent(pair.substring(eq + 1));
  });
  return {
    landing_domain: domain,
    geozo_block_id: parseInt(p.blockid || p.block || p.source) || null,
    geozo_site_id: parseInt(p.Siteid) || null,
    geozo_ad_id: parseInt(p.Adid || p.creative_id) || null,
    geozo_adgroup_id: parseInt(p.adgroupid || p.ad_campaign_id) || null,
    cost: p.cost || null
  };
}

const MAX_RESOLVES_PER_SCAN = 4;
const MAX_RECHECKS = 2;
const RESOLVE_DELAY_MS = 6000;

// CRITICAL: skip our own teasers
const safeTeasers = teasers.filter(t => !t.media_id || !ourAdIds.has(String(t.media_id)));
const newTeasers = safeTeasers.filter(t => t.click_url && t.media_id && !knownByMediaId.has(String(t.media_id)));
const knownTeasers = safeTeasers.filter(t => t.media_id && knownByMediaId.has(String(t.media_id)));
const noIdTeasers = safeTeasers.filter(t => !t.media_id && t.title && typeof t.title === 'string' && t.title.length > 3);

const results = [];
let clickIdx = 0;

// --- New teasers: click up to MAX_RESOLVES_PER_SCAN ---
const toResolve = newTeasers.slice(0, MAX_RESOLVES_PER_SCAN);
const queuedNew = newTeasers.slice(MAX_RESOLVES_PER_SCAN);

toResolve.forEach(t => {
  results.push({ json: {
    title: t.title, position: t.position,
    media_id: parseInt(t.media_id) || null,
    click_url: t.click_url,
    image_url: t.image_url || null,
    short_description: t.short_description || null,
    full_description: t.full_description || null,
    button_text: t.button_text || null,
    show_rate: t.show_rate || 0,
    render_domain: renderDomain, site_url: siteUrl,
    country_code: geo, proxy_url: proxyUrl,
    resolve_delay_ms: clickIdx * RESOLVE_DELAY_MS,
    needs_resolve: true, is_recheck: false
  }});
  clickIdx++;
});

// --- Re-check: pick oldest-rechecked known teasers with fresh click_url ---
const recheckCandidates = knownTeasers
  .filter(t => t.click_url)
  .sort((a, b) => {
    const aRow = knownByMediaId.get(String(a.media_id));
    const bRow = knownByMediaId.get(String(b.media_id));
    const aTime = aRow && aRow.last_rechecked_at ? new Date(aRow.last_rechecked_at).getTime() : 0;
    const bTime = bRow && bRow.last_rechecked_at ? new Date(bRow.last_rechecked_at).getTime() : 0;
    return aTime - bTime;
  })
  .slice(0, MAX_RECHECKS);

const recheckIds = new Set(recheckCandidates.map(t => String(t.media_id)));

recheckCandidates.forEach(t => {
  results.push({ json: {
    title: t.title, position: t.position,
    media_id: parseInt(t.media_id) || null,
    click_url: t.click_url,
    image_url: t.image_url || null,
    short_description: t.short_description || null,
    full_description: t.full_description || null,
    button_text: t.button_text || null,
    show_rate: t.show_rate || 0,
    render_domain: renderDomain, site_url: siteUrl,
    country_code: geo, proxy_url: proxyUrl,
    resolve_delay_ms: clickIdx * RESOLVE_DELAY_MS,
    needs_resolve: true, is_recheck: true
  }});
  clickIdx++;
});

// --- Known teasers (not being re-checked): use existing DB data ---
knownTeasers.filter(t => !recheckIds.has(String(t.media_id))).forEach(t => {
  const dbRow = knownByMediaId.get(String(t.media_id));
  const existingUrl = dbRow ? dbRow.destination_url || '' : '';
  const params = parseTrackingParams(existingUrl);
  results.push({ json: {
    title: t.title, position: t.position,
    media_id: parseInt(t.media_id) || null,
    click_url: t.click_url || null,
    image_url: t.image_url || null,
    short_description: t.short_description || null,
    full_description: t.full_description || null,
    button_text: t.button_text || null,
    show_rate: t.show_rate || 0,
    render_domain: renderDomain, site_url: siteUrl,
    country_code: geo, proxy_url: proxyUrl,
    needs_resolve: false, is_recheck: false,
    landing_url: existingUrl || null,
    landing_domain: params.landing_domain || null,
    geozo_block_id: params.geozo_block_id || null,
    geozo_site_id: params.geozo_site_id || null,
    geozo_ad_id: params.geozo_ad_id || null,
    geozo_adgroup_id: params.geozo_adgroup_id || null,
    cost: params.cost || null
  }});
});

// --- Queued new teasers: save without clicking, will be re-checked next scan ---
queuedNew.forEach(t => {
  results.push({ json: {
    title: t.title, position: t.position,
    media_id: parseInt(t.media_id) || null,
    click_url: null, image_url: t.image_url || null,
    short_description: t.short_description || null,
    full_description: t.full_description || null,
    button_text: t.button_text || null,
    show_rate: t.show_rate || 0,
    render_domain: renderDomain, site_url: siteUrl,
    country_code: geo, proxy_url: proxyUrl,
    needs_resolve: false, is_recheck: false,
    landing_url: null, landing_domain: null
  }});
});

// --- No-ID teasers: save as competitors without clicking ---
noIdTeasers.forEach(t => {
  results.push({ json: {
    title: t.title, position: t.position,
    media_id: null, click_url: t.click_url || null,
    image_url: t.image_url || null,
    short_description: t.short_description || null,
    full_description: t.full_description || null,
    button_text: t.button_text || null,
    show_rate: t.show_rate || 0,
    render_domain: renderDomain, site_url: siteUrl,
    country_code: geo, proxy_url: proxyUrl,
    needs_resolve: false, is_recheck: false,
    landing_url: null, landing_domain: null
  }});
});

if (results.length === 0) {
  return [{ json: { skip: true, site_url: siteUrl, country_code: geo } }];
}

return results;

// Wait before resolving to respect rate limits (3s between clicks)
const items = $input.all();
for (const item of items) {
  const delay = item.json.resolve_delay_ms || 0;
  if (delay > 0) {
    await new Promise(r => setTimeout(r, delay));
  }
}
return items;

// Process ALL items (not just first) — pair by index with Rate Limit Wait
const httpItems = $input.all();
const teaserItems = $('Rate Limit Wait').all();

// Geozo render domains — used to filter out tracker redirects
const isTrackerDomain = (url) => /render\.[a-zA-Z0-9-]+\.com/.test(url);

// Manual URL param parser (new URL() may not work in n8n sandbox)
function parseUrlParams(url) {
  if (!url || typeof url !== 'string') return { domain: null, params: {} };
  url = url.replace(/&amp;/g, '&');
  const domainMatch = url.match(/https?:\/\/([^/?#]+)/);
  const domain = domainMatch ? domainMatch[1] : null;
  const qIdx = url.indexOf('?');
  const p = {};
  if (qIdx !== -1) {
    url.substring(qIdx + 1).split('&').forEach(pair => {
      const eq = pair.indexOf('=');
      if (eq > 0) p[pair.substring(0, eq)] = decodeURIComponent(pair.substring(eq + 1));
    });
  }
  return { domain, params: p };
}

const results = [];

for (let i = 0; i < httpItems.length; i++) {
  const httpResponse = httpItems[i].json;
  const teaser = (teaserItems[i] || teaserItems[0]).json;

  let landingUrl = '';

  // 1. Check if HTTP Request followed redirects to a non-tracker domain
  if (httpResponse.url && !isTrackerDomain(httpResponse.url)) {
    landingUrl = httpResponse.url;
  } else if (httpResponse.responseUrl && !isTrackerDomain(httpResponse.responseUrl)) {
    landingUrl = httpResponse.responseUrl;
  }

  // 2. Parse HTML body for meta refresh / JS redirect
  if (!landingUrl) {
    const body = httpResponse.body || httpResponse.data || '';
    if (typeof body === 'string') {
      const metaMatch = body.match(/http-equiv=["']refresh["'][^>]*content=["'][^"']*url=([^"'\s>]+)/i);
      if (metaMatch) landingUrl = metaMatch[1].replace(/&amp;/g, '&');
      if (!landingUrl) {
        const jsMatch = body.match(/(?:window\.location|location\.href|location\.replace)\s*[=\(]\s*["']([^"']+)["']/i);
        if (jsMatch) landingUrl = jsMatch[1].replace(/&amp;/g, '&');
      }
    }
  }

  if (!landingUrl) landingUrl = 'resolve_failed';

  // Extract tracking params using manual parser
  const { domain, params: p } = parseUrlParams(landingUrl);
  const trackingParams = landingUrl.startsWith('http') ? {
    landing_domain: domain,
    geozo_block_id: parseInt(p.blockid || p.block || p.source) || null,
    geozo_site_id: parseInt(p.Siteid) || null,
    geozo_ad_id: parseInt(p.Adid || p.creative_id) || null,
    geozo_adgroup_id: parseInt(p.adgroupid || p.ad_campaign_id) || null,
    cost: p.cost || null
  } : {};

  results.push({ json: {
    title: teaser.title,
    position: teaser.position,
    media_id: teaser.media_id,
    click_url: teaser.click_url,
    image_url: teaser.image_url,
    short_description: teaser.short_description || null,
    full_description: teaser.full_description || null,
    button_text: teaser.button_text || null,
    render_domain: teaser.render_domain || null,
    landing_url: landingUrl,
    ...trackingParams,
    show_rate: teaser.show_rate || 0,
    is_recheck: teaser.is_recheck || false,
    site_url: teaser.site_url,
    country_code: teaser.country_code
  }});
}

return results;

// Merge ALL render HTML responses into ONE big string
// so Parse Teasers can process everything in a single pass
const items = $input.all();
const allHtml = items.map(i => {
  return String(i.json.data || i.json.body || '');
}).filter(h => h.length > 50).join('\n<!-- RENDER_SEPARATOR -->\n');

// Get metadata from ALL Extract Block IDs items (may be multiple sites)
const extractItems = $('Extract Block IDs').all().map(i => i.json);
const widgetItems = extractItems.filter(e => e.widget_found);
const meta = widgetItems[0] || extractItems[0] || {};

// Collect all unique block_ids and sites
const allBlockIds = [];
const seenBlocks = new Set();
widgetItems.forEach(e => {
  (e.block_ids || []).forEach(id => {
    if (!seenBlocks.has(id)) { seenBlocks.add(id); allBlockIds.push(id); }
  });
});
const allSites = [...new Set(widgetItems.map(e => e.site_url).filter(Boolean))];

return [{ json: {
  data: allHtml,
  site_url: meta.site_url || '',
  country_code: meta.country_code || '',
  block_ids: allBlockIds,
  all_sites: allSites,
  render_domain: meta.render_domain || '',
  user_agent: meta.user_agent || '',
  proxy_url: meta.proxy_url || '',
  accept_language: meta.accept_language || '',
  total_renders: items.length,
  renders_with_data: items.filter(i => String(i.json.data || i.json.body || '').length > 50).length,
  scanned_at: meta.scanned_at || $now.toISO()
}}];
